// pixelsorting on the main rendering chain
public int[] thresholdSort(int[] pixelArray, int mode) {
  boolean segmentFlag = false;
  int start = 0;
  int end = 0;
  float value;
  for (int i = 0; i < pixelArray.length; i++) {
    value = brightness(pixelArray[i]);

    if (!segmentFlag && evalPixel(value, mode, segmentFlag)) {
      start = i;
      segmentFlag = true;
    } else if (segmentFlag && (evalPixel(value, mode, segmentFlag) || i == pixelArray.length - 1)) {
      end = i;
      segmentFlag = false;
      int[] chunk = new int[end-start];
      for (int j = 0; j < end-start; j++) {
        chunk[j] = pixelArray[start+j];
      }
      chunk = sort(chunk);
      if (reverseSort) chunk = reverse(chunk);
      if (shiftSort) {
        int amount = round(chunk.length * noise(
          0.1f * i,
          frameCount * 0.0001f));
        chunk = shift(chunk, amount);
      }
      for (int j = 0; j < end-start; j++) {
        pixelArray[start+j] = chunk[j];
      }
    }
  }

  return pixelArray;
}

//----------------------------------------------------------------

public int[] shift(int[] array, int amount) {
  int[] shifted = new int[array.length];
  int j = 0;
  for (int i = 0; i < shifted.length; i++) {
    j = (i + amount) % array.length;
    shifted[i] = array[j < 0 ? j + array.length : j];
  }
  return shifted;
}

//================================================================
// Shaper functions

public float doubleExponentialSigmoid (float x, float a) {

  float epsilon = 0.00001f;
  float min_param_a = 0.0f + epsilon;
  float max_param_a = 1.0f - epsilon;
  a = constrain(a, min_param_a, max_param_a);
  a = 1.0f - a; // for sensible results

  float y = 0.0f;

  if (x <= 0.5f) {
    y = (pow(2.0f * x, 1.0f / a)) / 2.0f;
  } else {
    y = 1.0f - (pow(2.0f * (1.0f - x), 1.0f / a)) / 2.0f;
  }
  return y;
}

