class InputAnalyzer {
  AudioIn input;

  Amplitude amplitude;
  PitchDetector pitch;
  Waveform waveform;
  BeatDetector beat;
  FFT fft;

  int channel;
  int blockSize;
  int bands;
  float[] spectrum;

  InputAnalyzer(PApplet parent, int channel, int blockSize, int bands) {
    this.channel = channel;
    this.blockSize = blockSize;
    this.bands = bands;
    this.spectrum = new float[bands];

    try {
      this.input = new AudioIn(parent, this.channel);
      this.input.start();
    }
    catch(Exception e) {
      println("While initializing AudioIn: " + e);
      exit();
    }

    this.amplitude = new Amplitude(parent);
    this.amplitude.input(this.input);

    this.pitch = new PitchDetector(parent);
    this.pitch.input(this.input);

    this.waveform = new Waveform(parent, this.blockSize);
    this.waveform.input(this.input);

    this.beat = new BeatDetector(parent);
    this.beat.input(this.input);

    this.fft = new FFT(parent);
    this.fft.input(this.input);
  }

  public float[] getFFT() {
    this.fft.analyze(this.spectrum);
    return this.spectrum;
  }

  public Waveform getWaveform() {
    this.waveform.analyze();
    return this.waveform;
  }

  public float getAmplitude() {
    return this.amplitude.analyze();
  }

  public float getPitch() {
    return this.pitch.analyze();
  }

  public boolean isBeat() {
    return this.beat.isBeat();
  }

  public void drawWaveform(float scale, float yOffset) {
    this.waveform.analyze();
    beginShape();
    for (int i = 0; i < waveform.data.length; i++) {
      vertex(
        map(i, 0, waveform.data.length, 0, width),
        map(waveform.data[i], -1/scale, 1/scale, 0-yOffset, height-yOffset)
        );
    }
    endShape();
  }

  public void drawSpectrum() {
    this.fft.analyze(this.spectrum);
    for (int i = 0; i < this.spectrum.length; i++) {
      line(i, height, i, height - this.spectrum[i]*height*10 );
    }
  }
}
public void keyPressed() {
  switch(key) {
  case ' ':
    activePaletteA = palettes.get(PApplet.parseInt(random(palettes.size())));
    activePaletteA.randomizePastels();
    activePaletteB = palettes.get(PApplet.parseInt(random(palettes.size())));
    activePaletteB.randomizePastels();
    break;
  case 'a':
    shiftShader = !shiftShader; // toggle pixel shifting for just the shader
    break;
  case 's':
    sortShader = !sortShader; // toggle pixel sorting for just the shader
    break;
  case 'r':
    reverseSort = !reverseSort;
    break;
  case 'S':
    shiftSort = !shiftSort; // toggle pixel sorting for the feedback loop
    break;
  case 'i':
    devMode = !devMode;
    break;
  case 'm':
    sortMode ++;
    sortMode %= 8;
    break;
  case 'p':
    preProcess = !preProcess;
    break;
  case 'P':
    postProcess = !postProcess;
    break;
  }
}
//----------------------------------------------------------------
// Palettes are generated from swatches sampled from specific pastel pieces.





//================================================================

class Palette {
  String name;
  float[] background;
  float[][] pastels;

  Palette() {
    this.name = "";
    this.background = new float[]{};
    this.pastels = new float[][]{};
  }

  Palette(String _name, float[] _background, float[][] _pastels) {
    this.name = _name;
    this.background = _background;
    this.pastels = _pastels;
  }

  public Palette copy() {
    return new Palette(this.name, this.background, this.pastels);
  }

  //----------------------------------------------------------------

  public float[][] randomizePastels() {
    ArrayList<float[]> temp = new ArrayList<float[]>(this.pastels.length);
    for (int i = 0; i < this.pastels.length; i++) {
      temp.add(this.pastels[i]);
    }
    Collections.shuffle(temp);
    for (int i = 0; i < temp.size(); i++) {
      this.pastels[i] = temp.get(i);
    }
    return this.pastels;
  }

  //----------------------------------------------------------------

  public float[] getFlattenedPalette() {
    float[] flattened = new float[this.pastels.length * 4]; // 4 for RGBA
    for (int i = 0; i < this.pastels.length; i++) {
      for (int j = 0; j < this.pastels[i].length; j++) { // should iterate for RGB values
        flattened[i * 4 + j] = this.pastels[i][j];
      }
      flattened[i * 4 + 3] = 1.0f; // manually set the A to 1.0
    }
    return flattened;
  }
}

